<?php
namespace Database\Seeders;
use App\Models\GuildUnion;use App\Models\PostCategory;use App\Models\User;use App\Models\Video;use Illuminate\Database\Seeder;
class VideoSeeder extends Seeder{public function run():void{$admin=User::first();$cat=PostCategory::where('slug','services-systems')->first();$unions=GuildUnion::all()->values();$titles=['معرفی خدمات اتاق اصناف گرگان','گزارش طرح نظارت بازار','آموزش ثبت درخواست صنفی','مصاحبه رئیس اتاق اصناف','گزارش دوره آموزشی اصناف'];foreach($titles as $i=>$title){$upload=$i%2===1;Video::updateOrCreate(['slug'=>'video-'.($i+1)],['title'=>$title,'description'=>'ویدیوی نمونه برای تست آرشیو و صفحه جزئیات ویدیو.','cover_image'=>'assets/img/asnaf-gorgan-default.jpg','video_type'=>$upload?'upload':'aparat','video_file'=>$upload?'assets/video/fallback.mp4':null,'aparat_url'=>$upload?null:'https://www.aparat.com/video/video/embed/videohash/sample/vt/frame','category_id'=>$cat?->id,'union_id'=>$unions->isNotEmpty()?$unions[$i%$unions->count()]->id:null,'status'=>'published','published_at'=>now()->subDays($i),'created_by'=>$admin?->id,'approved_by'=>$admin?->id,'sort_order'=>$i+1,'is_active'=>true]);}}}
